SELECT team_member_name, email, role, project_id
FROM team_members
ORDER BY team_member_name ASC;

SELECT meeting_id, meeting_datetime
FROM meetings
WHERE meeting_datetime BETWEEN '2016-02-01' AND '2016-02-28';

SELECT DISTINCT tm.team_member_name, tm.role, p.project_name
FROM team_members tm
JOIN projects p ON tm.project_id = p.project_id;

SELECT project_id, COUNT(*) AS number_of_meetings
FROM meetings
GROUP BY project_id;
